def upsert_heartbeat_runtime_state(
    *,
    state_id: str,
    last_tick_id: str,
    last_tick_at: str,
    next_tick_at: str,
    schedule_state: str,
    due: bool,
    last_decision_type: str,
    last_result: str,
    blocked_reason: str,
    currently_ticking: bool,
    last_trigger_source: str,
    scheduler_active: bool,
    scheduler_started_at: str,
    scheduler_stopped_at: str,
    scheduler_health: str,
    recovery_status: str,
    last_recovery_at: str,
    provider: str,
    model: str,
    lane: str,
    model_source: str,
    resolution_status: str,
    fallback_used: bool,
    execution_status: str,
    parse_status: str,
    budget_status: str,
    last_ping_eligible: bool,
    last_ping_result: str,
    last_action_type: str,
    last_action_status: str,
    last_action_summary: str,
    last_action_artifact: str,
    updated_at: str,
) -> dict[str, object]:
    with connect() as conn:
        conn.execute(
            """
            INSERT INTO heartbeat_runtime_state (
                id,
                state_id,
                last_tick_id,
                last_tick_at,
                next_tick_at,
                schedule_state,
                due,
                last_decision_type,
                last_result,
                blocked_reason,
                currently_ticking,
                last_trigger_source,
                scheduler_active,
                scheduler_started_at,
                scheduler_stopped_at,
                scheduler_health,
                recovery_status,
                last_recovery_at,
                provider,
                model,
                lane,
                model_source,
                resolution_status,
                fallback_used,
                execution_status,
                parse_status,
                budget_status,
                last_ping_eligible,
                last_ping_result,
                last_action_type,
                last_action_status,
                last_action_summary,
                last_action_artifact,
                updated_at
            )
            VALUES (1, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                state_id = excluded.state_id,
                last_tick_id = excluded.last_tick_id,
                last_tick_at = excluded.last_tick_at,
                next_tick_at = excluded.next_tick_at,
                schedule_state = excluded.schedule_state,
                due = excluded.due,
                last_decision_type = excluded.last_decision_type,
                last_result = excluded.last_result,
                blocked_reason = excluded.blocked_reason,
                currently_ticking = excluded.currently_ticking,
                last_trigger_source = excluded.last_trigger_source,
                scheduler_active = excluded.scheduler_active,
                scheduler_started_at = excluded.scheduler_started_at,
                scheduler_stopped_at = excluded.scheduler_stopped_at,
                scheduler_health = excluded.scheduler_health,
                recovery_status = excluded.recovery_status,
                last_recovery_at = excluded.last_recovery_at,
                provider = excluded.provider,
                model = excluded.model,
                lane = excluded.lane,
                model_source = excluded.model_source,
                resolution_status = excluded.resolution_status,
                fallback_used = excluded.fallback_used,
                execution_status = excluded.execution_status,
                parse_status = excluded.parse_status,
                budget_status = excluded.budget_status,
                last_ping_eligible = excluded.last_ping_eligible,
                last_ping_result = excluded.last_ping_result,
                last_action_type = excluded.last_action_type,
                last_action_status = excluded.last_action_status,
                last_action_summary = excluded.last_action_summary,
                last_action_artifact = excluded.last_action_artifact,
                updated_at = excluded.updated_at
            """,
            (
                state_id,
                last_tick_id,
                last_tick_at,
                next_tick_at,
                schedule_state,
                1 if due else 0,
                last_decision_type,
                last_result,
                blocked_reason,
                1 if currently_ticking else 0,
                last_trigger_source,
                1 if scheduler_active else 0,
                scheduler_started_at,
                scheduler_stopped_at,
                scheduler_health,
                recovery_status,
                last_recovery_at,
                provider,
                model,
                lane,
                model_source,
                resolution_status,
                1 if fallback_used else 0,
                execution_status,
                parse_status,
                budget_status,
                1 if last_ping_eligible else 0,
                last_ping_result,
                last_action_type,
                last_action_status,
                last_action_summary,
                last_action_artifact,
                updated_at,
            ),
        )
        conn.commit()
    state = get_heartbeat_runtime_state()
    if state is None:
        raise RuntimeError("heartbeat runtime state was not persisted")
    return state


def record_runtime_action_outcome(
    *,
    action_id: str,
    decision_mode: str,
    decision_reason: str,
    decision_score: float,
    payload_json: dict[str, object] | None,
    result_status: str,
    result_summary: str,
    result_json: dict[str, object] | None,
    recorded_at: str,
) -> dict[str, object]:
    outcome_id = f"rao-{uuid4().hex[:12]}"
    with connect() as conn:
        conn.execute(
            """
            INSERT INTO runtime_action_outcomes (
                outcome_id,
                action_id,
                decision_mode,
                decision_reason,
                decision_score,
                payload_json,
                result_status,
                result_summary,
                result_json,
                recorded_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                outcome_id,
                action_id,
                decision_mode,
                decision_reason,
                float(decision_score or 0.0),
                _json.dumps(payload_json or {}, ensure_ascii=False, sort_keys=True),
                result_status,
                result_summary,
                _json.dumps(result_json or {}, ensure_ascii=False, sort_keys=True),
                recorded_at,
            ),
        )
        conn.commit()
    with connect() as conn:
        row = conn.execute(
            """
            SELECT
                outcome_id,
                action_id,
                decision_mode,
                decision_reason,
                decision_score,
                payload_json,
                result_status,
                result_summary,
                result_json,
                recorded_at
            FROM runtime_action_outcomes
            WHERE outcome_id = ?
            """,
            (outcome_id,),
        ).fetchone()
    if row is None:
        raise RuntimeError("runtime action outcome was not persisted")
    return _runtime_action_outcome_from_row(row)


